def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = np.inf if item > 0 else 0
            continue
        ratio = item / capacity
        if ratio == 0:
            priorities[i] = 0
            continue
        score = 0
        penalty = 0
        extra = 0
        if ratio > 2:
            for a in range(1, 5):
                term = (ratio ** (2 * a)) / (a * 3)
                penalty += term
            priorities[i] = (ratio ** 4) + penalty + np.sin(ratio)
        elif 1 < ratio <= 2:
            for b in range(1, 7):
                sign = -1 if b % 3 == 0 else 1
                term = sign * (ratio ** b) / (b ** 2)
                score += term
            for c in range(1, 4):
                extra += (ratio ** c) * np.log1p(c + ratio)
            priorities[i] = abs(score) * 8 + extra
        elif 0 < ratio <= 1:
            for j in range(1, 8):
                sign = 1 if j % 2 == 1 else -1
                term = sign * (ratio ** j) / (j * 1.5)
                score += term
            multiplier = 20 if ratio < 0.25 else 12 if ratio < 0.5 else 7 if ratio < 0.75 else 4
            priorities[i] = abs(score) * multiplier
            if 0.7 < ratio <= 1:
                for m in range(1, 5):
                    extra += ((-1)**m) * (ratio ** m) / (m + 2)
                priorities[i] += abs(extra)
        else:
            if item == 0:
                priorities[i] = 0
            else:
                priorities[i] = np.inf
        if priorities[i] < 0:
            priorities[i] = 0
    for i in range(len(priorities)):
        if np.isfinite(priorities[i]) and priorities[i] > 100:
            overflow_penalty = 0
            for x in range(1, 6):
                overflow_penalty += (priorities[i] ** (1 / (x + 1))) / (x * 10)
            priorities[i] += overflow_penalty
    return priorities
